const QUESTIONS = {
  ciencias: [
    // ETAPA 1: Imunidade e Vacinas (40 questões)
    {id:1, stage:1, difficulty:'easy', category:'conceitos', theme:'anticorpos', q:"Anticorpos são:", alt:["Proteínas de defesa produzidas pelo sistema imune","Vírus enfraquecidos usados em vacinas","Bactérias boas do intestino","Minerais essenciais da alimentação"], c:0, e:"Anticorpos são proteínas do sistema imune que se ligam a microrganismos invasores e ajudam a destruí-los."},
    {id:2, stage:1, difficulty:'easy', category:'vacinas', theme:'prevenção', q:"A vacina serve principalmente para:", alt:["Tratar doenças já instaladas","Prevenir doenças antes do contágio","Substituir antibióticos","Curar ferimentos na pele"], c:1, e:"Vacinas são preventivas. Estimulam o corpo a produzir anticorpos e memória imunológica."},
    {id:3, stage:1, difficulty:'easy', category:'soro', theme:'tratamento', q:"O soro terapêutico contém:", alt:["Anticorpos prontos para ação imediata","Vírus vivos atenuados","Antibióticos de amplo espectro","Hormônios estimulantes"], c:0, e:"Soros possuem anticorpos prontos, indicados para tratamento pós-exposição com ação rápida e temporária."},
    {id:4, stage:1, difficulty:'easy', category:'epidemiologia', theme:'definições', q:"Aumento rápido de casos de uma doença em uma região define:", alt:["Pandemia","Endemia","Epidemia","Imunidade coletiva"], c:2, e:"Epidemia = surto localizado e repentino com aumento significativo de casos."},
    {id:5, stage:1, difficulty:'easy', category:'epidemiologia', theme:'definições', q:"Doença constante em uma região, com número médio de casos ao longo do tempo, é:", alt:["Endemia","Epidemia","Pandemia","Surtos isolados"], c:0, e:"Endemia = presença contínua e esperada da doença em determinada área geográfica."},
    {id:6, stage:1, difficulty:'easy', category:'epidemiologia', theme:'definições', q:"O prefixo 'PAN' em pandemia refere-se a:", alt:["Região específica","Mundo inteiro (planeta)","Apenas animais","Clima quente"], c:1, e:"PAN = todos. Pandemia = doença espalhada globalmente, afetando múltiplos países."},
    {id:7, stage:1, difficulty:'medium', category:'vacinas', theme:'imunidade_coletiva', q:"Qual afirmação sobre vacinas é VERDADEIRA?", alt:["Causam a doença que pretendem prevenir","Substituem completamente a higiene pessoal","Protegem apenas o indivíduo vacinado","Reduzem a circulação do patógeno na população"], c:3, e:"A vacinação em massa cria imunidade de rebanho, reduzindo a transmissão e protegendo quem não pode se vacinar."},
    {id:8, stage:1, difficulty:'medium', category:'soro', theme:'aplicação', q:"Uma pessoa picada por cobra peçonhenta deve receber:", alt:["Vacina antiofídica preventiva","Soro antiofídico para neutralizar a peçonha","Antibiótico de amplo espectro","Anti-inflamatório para dor"], c:1, e:"Soro antiofídico contém anticorpos prontos que neutralizam a peçonha já no organismo. Ação imediata é crucial."},
    {id:9, stage:1, difficulty:'medium', category:'fake_news', theme:'identificação', q:"Fake news em saúde geralmente NÃO apresenta:", alt:["Apelo ao medo ou urgência","Promessas de curas milagrosas","Fontes científicas e referências verificáveis","Emojis e linguagem sensacionalista"], c:2, e:"Notícias falsas carecem de respaldo científico, fontes confiáveis e referências verificáveis."},
    {id:10, stage:1, difficulty:'medium', category:'imunidade', theme:'comparação', q:"Comparando imunidade natural (após doença) vs vacina:", alt:["A imunidade natural é sempre superior","A vacina gera resposta mais segura e controlada","São idênticas em eficácia e segurança","A vacina causa mais efeitos colaterais graves"], c:1, e:"Vacinas simulam a infecção sem os riscos da doença real, gerando proteção com menor risco."},
    {id:11, stage:1, difficulty:'medium', category:'antibióticos', theme:'especificidade', q:"Antibióticos NÃO funcionam contra:", alt:["Bactérias Gram-positivas","Vírus","Protozoários como o da malária","Fungos causadores de micoses"], c:1, e:"Antibióticos atacam estruturas específicas de bactérias. Vírus não possuem essas estruturas."},
    {id:12, stage:1, difficulty:'medium', category:'saúde_pública', theme:'sus', q:"O SUS oferece vacinas gratuitamente porque:", alt:["É obrigação constitucional garantir saúde preventiva","Gera lucro para a indústria farmacêutica","É teste clínico em larga escala","Substitui a necessidade de médicos"], c:0, e:"A Constituição garante direito à saúde. Vacinação coletiva é política pública de prevenção."},
    {id:13, stage:1, difficulty:'medium', category:'fake_news', theme:'desinformação', q:"Se uma mensagem diz que 'vacina de mRNA altera DNA humano', é provável que seja:", alt:["Fato científico amplamente aceito","Fake news sem base em evidências","Novidade médica revolucionária","Consenso da comunidade científica"], c:1, e:"Vacinas de mRNA atuam no citoplasma, não entram no núcleo onde está o DNA. Não alteram genoma humano."},
    {id:14, stage:1, difficulty:'medium', category:'lógica', theme:'falácias', q:"A expressão 'post hoc ergo propter hoc' alerta para:", alt:["Efeito colateral vacinal","Correlação não implica causalidade","Mutação viral acelerada","Prevenção primária eficaz"], c:1, e:"Falácia lógica: 'depois disso, logo causado por isso'. Ex: galo canta antes do sol, mas não causa o nascer."},
    {id:15, stage:1, difficulty:'hard', category:'vacinas', theme:'atualização', q:"Por que a vacina da gripe precisa ser atualizada anualmente?", alt:["Bactérias desenvolvem resistência rapidamente","O vírus da gripe sofre mutações frequentes (drift antigênico)","O SUS quer vender mais doses","A vacina perde validade no calor"], c:1, e:"Alta taxa de mutação do influenza exige atualização anual para acompanhar variantes circulantes."},
    {id:16, stage:1, difficulty:'hard', category:'imunidade', theme:'rebanho', q:"Imunidade de rebanho ocorre quando:", alt:["Todos tomam soro preventivo","Maioria está imune, criando barreira epidemiológica","Animais são vacinados em massa","A doença some espontaneamente"], c:1, e:"Quando % suficiente da população está imune, a transmissão é interrompida, protegendo vulneráveis."},
    {id:17, stage:1, difficulty:'hard', category:'pesquisa', theme:'ensaios_clínicos', q:"Em um ensaio clínico fase 3, o grupo controle geralmente recebe:", alt:["Vacina experimental em dose reduzida","Placebo ou soro fisiológico","Nenhuma intervenção","Antibiótico profilático"], c:1, e:"Grupo controle recebe placebo para comparar efeitos reais da vacina vs efeitos psicológicos/naturais."},
    {id:18, stage:1, difficulty:'hard', category:'soro', theme:'indicação', q:"O soro antitetânico é aplicado quando:", alt:["Carteira de vacinação está em dia","Há ferimento sujo/profundo + vacinação incerta/defasada","Para prevenir gripe sazonal","No tratamento da cólera"], c:1, e:"Imunização passiva emergencial: anticorpos prontos para neutralizar toxina tetânica já produzida."},
    {id:19, stage:1, difficulty:'easy', category:'viroses', theme:'poliomielite', q:"A poliomielite pode causar como complicação grave:", alt:["Manchas vermelhas na pele","Paralisia muscular, especialmente em crianças","Diarreia aquosa intensa","Tosse seca persistente"], c:1, e:"O vírus ataca neurônios motores da medula, podendo paralisar membros. Vacina é a prevenção."},
    {id:20, stage:1, difficulty:'easy', category:'vacinas', theme:'tríplice_viral', q:"O sarampo é prevenido pela vacina:", alt:["BCG (aplicada no braço)","Tríplice viral (sarampo, caxumba, rubéola)","Pentavalente (5 doenças)","HPV (papilomavírus)"], c:1, e:"Tríplice viral protege contra Sarampo, Caxumba e Rubéola. Calendário infantil básico."},
    {id:21, stage:1, difficulty:'medium', category:'viroses', theme:'rubéola', q:"A rubéola é perigosa principalmente para:", alt:["Idosos acima de 70 anos","Crianças pequenas abaixo de 2 anos","Gestantes, especialmente no 1º trimestre","Homens adultos"], c:2, e:"Pode atravessar a placenta e causar síndrome da rubéola congênita: surdez, catarata, cardiopatia fetal."},
    {id:22, stage:1, difficulty:'medium', category:'viroses', theme:'caxumba', q:"A caxumba pode causar esterilidade principalmente em:", alt:["Crianças pré-púberes","Adolescentes e adultos pós-puberdade","Idosos acima de 60 anos","Animais domésticos"], c:1, e:"Inflamação dos testículos (orquite) ou ovários pode ocorrer em pós-puberdade, com risco de infertilidade."},
    {id:23, stage:1, difficulty:'medium', category:'história', theme:'varíola', q:"A varíola foi erradicada globalmente em 1980 graças a:", alt:["Antibióticos de amplo espectro","Campanhas de vacinação em massa coordenadas pela OMS","Isolamento total de doentes por décadas","Melhoria espontânea da higiene"], c:1, e:"Única doença humana erradicada por esforço global de vacinação. Último caso natural em 1977."},
    {id:24, stage:1, difficulty:'medium', category:'nutrição', theme:'mitos', q:"Qual vitamina NÃO previne doenças virais diretamente?", alt:["Vitamina A (importante para mucosas)","Vitamina C (apoia imunidade)","Vitamina D (modula resposta imune)","Todas são 'curas milagrosas' contra vírus"], c:3, e:"Vitaminas apoiam o sistema imune, mas não substituem vacinas, higiene ou tratamento específico."},
    {id:25, stage:1, difficulty:'medium', category:'viroses', theme:'raiva', q:"A raiva também é conhecida como 'hidrofobia' porque:", alt:["Causa febre muito alta","Provoca medo de água devido a espasmos na deglutição","Sempre vem com catapora","É transmitida por água contaminada"], c:1, e:"Espasmos dolorosos na garganta ao tentar engolir geram aversão à água. Sinal neurológico grave."},
    {id:26, stage:1, difficulty:'medium', category:'prevenção', theme:'animais', q:"Animais vacinados contra raiva:", alt:["Transmitem mais o vírus","Não espalham o vírus, quebrando o ciclo zoonótico","Ficam agressivos temporariamente","Devem ser soltos na natureza"], c:1, e:"Vacinação animal é estratégia eficaz de saúde pública para interromper transmissão para humanos."},
    {id:27, stage:1, difficulty:'medium', category:'emergência', theme:'raiva', q:"Se você for mordido por animal suspeito de raiva, deve:", alt:["Esperar sintomas aparecerem para confirmar","Lavar com água e sabão e procurar atendimento médico imediatamente","Tomar chá de ervas calmantes","Ignorar se o animal parecer saudável"], c:1, e:"Higiene imediata + avaliação médica para profilaxia pós-exposição (vacina/soro) salvam vidas."},
    {id:28, stage:1, difficulty:'medium', category:'viroses', theme:'raiva', q:"O vírus da raiva afeta principalmente qual sistema?", alt:["Sistema digestório","Sistema respiratório","Sistema nervoso central","Sistema tegumentar (pele)"], c:2, e:"Migra pelos nervos periféricos até o cérebro, causando encefalite fatal se não tratada precocemente."},
    {id:29, stage:1, difficulty:'medium', category:'história', theme:'revolta_vacina', q:"A vacinação obrigatória em 1904 no Rio de Janeiro gerou:", alt:["Revolta da Vacina, com protestos populares","Comemoração espontânea da população","Nenhuma reação significativa","Protestos exclusivamente ambientais"], c:0, e:"Conflito histórico por falta de informação e abordagem autoritária. Lição sobre comunicação em saúde."},
    {id:30, stage:1, difficulty:'medium', category:'história', theme:'jenner', q:"Edward Jenner criou a primeira vacina usando material de:", alt:["Cachorros raivosos","Gatos com infecções","Varíola bovina (vaccinia) em ordenhadoras","Plantas medicinais"], c:2, e:"Observou que ordenhadoras com varíola bovina não pegavam varíola humana. Vaccina → vacina."},
    {id:31, stage:1, difficulty:'hard', category:'vacinas', theme:'eficácia', q:"Dizer que uma vacina tem 90% de eficácia NÃO significa que:", alt:["Reduz em 90% o risco de doença sintomática","100% dos vacinados estarão protegidos individualmente","Diminui drasticamente casos graves e mortes","Contribui para controle populacional da doença"], c:1, e:"Eficácia é medida populacional. Nenhum imunobiológico é 100% eficaz para cada indivíduo."},
    {id:32, stage:1, difficulty:'hard', category:'pesquisa', theme:'fases', q:"Para ser aprovada, uma vacina passa por fases que incluem:", alt:["Apenas opinião de especialistas renomados","Testes em animais, depois humanos (fases 1-3) com milhares de voluntários","Venda direta após testes em 10 pessoas","Aprovação baseada apenas em dados de outros países"], c:1, e:"Fases rigorosas: segurança (fase 1), dosagem/imunogenicidade (fase 2), eficácia/segurança em larga escala (fase 3)."},
    {id:33, stage:1, difficulty:'hard', category:'imunologia', theme:'antígeno', q:"O termo 'antígeno' refere-se a:", alt:["Defesa produzida pelo corpo (anticorpo)","Qualquer substância que desencadeia resposta imune específica","Remédio antiviral genérico","Anticorpo pronto em soroterapia"], c:1, e:"Parte do patógeno (proteína, carboidrato) que o sistema imune reconhece como estranho e ataca."},
    {id:34, stage:1, difficulty:'hard', category:'imunologia', theme:'memória', q:"A memória imunológica permite que:", alt:["Fiquemos doentes sempre pelo mesmo agente","O corpo reaja mais rápido e forte na 2ª exposição ao mesmo antígeno","Precisemos de soro toda vez que adoecemos","Anticorpos desapareçam após a infecção"], c:1, e:"Células B e T de memória persistem, acelerando produção de anticorpos em reexposições."},
    {id:35, stage:1, difficulty:'hard', category:'vetores', theme:'definição', q:"Qual NÃO é considerado vetor biológico de doenças?", alt:["Mosquito Anopheles (malária)","Carrapato (febre maculosa)","Barbeiro (doença de Chagas)","Seringa contaminada (hepatites)"], c:3, e:"Seringa é veículo/fômite (objeto inanimado). Vetor biológico é organismo vivo que transmite ativamente."},
    {id:36, stage:1, difficulty:'hard', category:'transmissão', theme:'vertical', q:"A transmissão vertical de doenças ocorre:", alt:["De pai para filho por contato físico","De mãe para feto/bebê durante gestação, parto ou amamentação","De animal para humano por mordida","De pessoa para pessoa por água contaminada"], c:1, e:"Exemplos: HIV, sífilis, rubéola, Zika. Prevenção inclui tratamento materno e parto seguro."},
    {id:37, stage:1, difficulty:'hard', category:'imunidade', theme:'proteção_coletiva', q:"A 'imunidade coletiva' protege principalmente:", alt:["Apenas quem foi vacinado","Vacinados E não vacinados vulneráveis (imunodeprimidos, alérgicos)","Somente profissionais de saúde","Ninguém, é conceito teórico"], c:1, e:"Reduz circulação do patógeno, criando escudo epidemiológico para quem não pode desenvolver imunidade."},
    {id:38, stage:1, difficulty:'easy', category:'conceitos', theme:'defesas', q:"Além dos anticorpos, outra defesa não específica do corpo é:", alt:["Produção de insulina","Barreiras físicas como pele e mucosas","Síntese de hemoglobina","Digestão de proteínas"], c:1, e:"Pele íntegra, muco, cílios, pH ácido do estômago são barreiras inatas que impedem entrada de patógenos."},
    {id:39, stage:1, difficulty:'easy', category:'vacinas', theme:'calendário', q:"A caderneta de vacinação serve para:", alt:["Registrar apenas vacinas obrigatórias","Acompanhar histórico vacinal e orientar próximas doses","Substituir consultas médicas","Comprovar renda familiar"], c:1, e:"Documento essencial para monitorar imunizações conforme calendário do PNI/SUS por faixa etária."},
    {id:40, stage:1, difficulty:'medium', category:'saúde_pública', theme:'pni', q:"O Programa Nacional de Imunizações (PNI) do Brasil é referência mundial porque:", alt:["Oferece apenas vacinas importadas","Garante acesso gratuito e universal a múltiplas vacinas pelo SUS","Funciona apenas em grandes cidades","Substitui a necessidade de saneamento"], c:1, e:"Um dos maiores programas públicos de vacinação do mundo, com calendário abrangente e distribuição nacional."},
    
    // ETAPA 2: Doenças Virais (40 questões)
    {id:41, stage:2, difficulty:'easy', category:'covid19', theme:'agente', q:"O SARS-CoV-2 causa qual doença?", alt:["Gripe sazonal","Covid-19","Dengue hemorrágica","Tétano generalizado"], c:1, e:"Vírus da família Coronaviridae, identificado em 2019, responsável pela pandemia global."},
    {id:42, stage:2, difficulty:'easy', category:'dengue', theme:'vetor', q:"A dengue é transmitida principalmente por:", alt:["Água de torneira não tratada","Picada do mosquito Aedes aegypti","Contato físico com doentes","Inalação de aerossóis em locais fechados"], c:1, e:"Aedes aegypti é vetor urbano. Fêmea pica durante o dia e deposita ovos em água parada limpa ou suja."},
    {id:43, stage:2, difficulty:'easy', category:'zika', theme:'complicações', q:"A infecção por Zika em gestantes pode causar no feto:", alt:["Paralisia cerebral adquirida","Microcefalia e outras malformações neurológicas","Diabetes tipo 1 congênito","Cegueira por catarata isolada"], c:1, e:"Vírus atravessa placenta e compromete desenvolvimento cerebral intrauterino. Síndrome congênita da Zika."},
    {id:44, stage:2, difficulty:'easy', category:'chikungunya', theme:'sintomas', q:"Chikungunya tem como sintoma característico:", alt:["Tosse produtiva com catarro","Dores articulares intensas e prolongadas","Diarreia com sangue","Manchas roxas espontâneas"], c:1, e:"Artralgia severa pode persistir por meses/anos, afetando qualidade de vida. Nome significa 'aqueles que se dobram'."},
    {id:45, stage:2, difficulty:'easy', category:'febre_amarela', theme:'urbana', q:"A febre amarela urbana no Brasil:", alt:["É comum e endêmica em todas as regiões","Foi erradicada (último caso em 1942)","Só existe no Nordeste","É forma leve sem risco de morte"], c:1, e:"Controlada por vacinação e combate ao Aedes. Forma silvestre ainda circula em áreas de mata."},
    {id:46, stage:2, difficulty:'easy', category:'febre_amarela', theme:'macacos', q:"Na febre amarela silvestre, os macacos são:", alt:["Culpados pela transmissão","Vítimas e sentinelas da circulação viral","Vetores biológicos ativos","Imunes e não adoecem"], c:1, e:"Bugios, saguis e outros primatas adoecem e morrem. Sua morte alerta para risco humano na região."},
    {id:47, stage:2, difficulty:'medium', category:'covid19', theme:'transmissão', q:"A covid-19 se espalha principalmente por:", alt:["Apenas contato direto pele a pele","Gotículas respiratórias e aerossóis no ar","Comida crua ou mal cozida","Picada de mosquitos noturnos"], c:1, e:"Respiração próxima, fala, tosse e espirro liberam partículas. Ambientes fechados e mal ventilados amplificam risco."},
    {id:48, stage:2, difficulty:'medium', category:'covid19', theme:'prevenção', q:"Para reduzir transmissão da covid-19, a estratégia mais eficaz combina:", alt:["Uso exclusivo de álcool em gel","Máscara + distância + ventilação + vacinação","Isolamento total por tempo indeterminado","Apenas vacina, dispensando outras medidas"], c:1, e:"Abordagem em camadas ('queijo suíço'): nenhuma medida é 100%, mas juntas reduzem risco drasticamente."},
    {id:49, stage:2, difficulty:'medium', category:'diagnóstico', theme:'pcr', q:"O teste PCR para covid-19 detecta:", alt:["Anticorpos produzidos pelo paciente","Material genético (RNA) do vírus","Células brancas do sangue aumentadas","Bactérias secundárias na pneumonia"], c:1, e:"Amplifica sequências específicas do RNA viral. Ideal para diagnóstico agudo (primeira semana de sintomas)."},
    {id:50, stage:2, difficulty:'medium', category:'diagnóstico', theme:'sorologia', q:"A sorologia na covid-19 detecta:", alt:["Vírus vivo circulante","Resposta imunológica (anticorpos IgG/IgM)","Sintomas clínicos específicos","RNA viral em amostra nasal"], c:1, e:"Indica infecção passada ou resposta vacinal. Não serve para diagnóstico agudo (leva dias para produzir anticorpos)."},
    {id:51, stage:2, difficulty:'medium', category:'saúde_pública', theme:'lockdown', q:"O lockdown visa principalmente:", alt:["Aumentar o turismo interno","Evitar colapso do sistema de saúde","Fechar escolas permanentemente","Substituir a necessidade de vacinas"], c:1, e:"Medida extrema para reduzir velocidade de transmissão, ganhando tempo para ampliar leitos, equipamentos e vacinação."},
    {id:52, stage:2, difficulty:'medium', category:'dengue', theme:'criadouro', q:"O Aedes aegypti se reproduz em:", alt:["Água corrente de rios e cachoeiras","Qualquer recipiente com água parada, limpa ou suja","Apenas em lixo orgânico em decomposição","Só em rios e lagos naturais"], c:1, e:"Pneus, garrafas, vasos, calhas, caixas d'água abertas. Eliminar água parada semanalmente é a prevenção chave."},
    {id:53, stage:2, difficulty:'medium', category:'dengue', theme:'ciclo', q:"O ciclo de vida do Aedes aegypti, do ovo ao adulto, leva cerca de:", alt:["1 mês em condições ideais","7-10 dias em temperatura favorável","1 ano completo","Apenas 2 dias"], c:1, e:"Rápido em clima quente. Por isso, inspeção e eliminação de criadouros deve ser semanal, não mensal."},
    {id:54, stage:2, difficulty:'medium', category:'dengue', theme:'hemorrágica', q:"A dengue hemorrágica ocorre com mais frequência em:", alt:["Primeira infecção por qualquer sorotipo","Segunda infecção por sorotipo diferente do primeiro","Pessoas que tomaram vacina recentemente","Apenas em crianças abaixo de 5 anos"], c:1, e:"Anticorpos não neutralizantes da 1ª infecção podem facilitar entrada do vírus em células na 2ª infecção (ADE)."},
    {id:55, stage:2, difficulty:'medium', category:'dengue', theme:'alarme', q:"Sintoma de alarme na dengue que indica necessidade de atendimento urgente:", alt:["Apenas coceira na pele","Dor abdominal intensa, sangramento, letargia","Manchas vermelhas leves sem febre","Tosse seca ocasional"], c:1, e:"Sinais de extravasamento plasmático e choque. Hidratação venosa e monitoramento hospitalar são essenciais."},
    {id:56, stage:2, difficulty:'medium', category:'febre_amarela', theme:'silvestre', q:"A febre amarela silvestre é transmitida por mosquitos dos gêneros:", alt:["Aedes e Culex","Haemagogus e Sabethes","Anopheles e Lutzomyia","Pulga e carrapato"], c:1, e:"Mosquitos de mata. Humanos infectados podem reintroduzir vírus em áreas urbanas se houver Aedes presente."},
    {id:57, stage:2, difficulty:'medium', category:'zika', theme:'transmissão_alternativa', q:"Além da picada do mosquito, a Zika pode ser transmitida por:", alt:["Beijo na boca","Relação sexual e transfusão de sangue","Ar condicionado central","Picada de cobra peçonhenta"], c:1, e:"Vírus persiste no sêmen por meses. Recomenda-se uso de preservativo após viagem a áreas endêmicas."},
    {id:58, stage:2, difficulty:'medium', category:'poliomielite', theme:'transmissão', q:"A poliomielite é transmitida principalmente via:", alt:["Aerossóis respiratórios","Fecal-oral (água/alimentos contaminados com fezes)","Picada de mosquito vetor","Transfusão de sangue infectado"], c:1, e:"Vírus eliminado nas fezes contamina ambiente. Saneamento e vacinação são pilares da erradicação."},
    {id:59, stage:2, difficulty:'medium', category:'caxumba', theme:'alvo', q:"A caxumba ataca principalmente qual estrutura?", alt:["Rins e bexiga","Glândulas salivares parótidas (próximas às orelhas)","Fígado e vesícula","Coração e válvulas"], c:1, e:"Parotidite: inchaço característico na região das orelhas. Pode complicar com orquite/ooferite em adultos."},
    {id:60, stage:2, difficulty:'medium', category:'catapora', theme:'complicações', q:"A catapora (varicela) pode deixar cicatrizes se:", alt:["As bolhas forem coçadas, permitindo infecção bacteriana secundária","O paciente tomar antibiótico preventivo","Houver exposição solar moderada","A febre for controlada com antitérmicos"], c:0, e:"Coçar rompe bolhas e introduz bactérias da pele. Manter unhas curtas e usar antipruriginosos ajuda."},
    {id:61, stage:2, difficulty:'medium', category:'gripe', theme:'diferença', q:"Diferença principal entre gripe e resfriado comum:", alt:["São doenças idênticas causadas pelo mesmo vírus","Gripe tem febre alta, dores musculares e prostração; resfriado é mais leve","Resfriado é viral, gripe é bacteriana","Gripe não tem vacina disponível"], c:1, e:"Influenza (gripe) é mais sistêmico e grave. Resfriado: rinovírus, sintomas leves, sem febre alta."},
    {id:62, stage:2, difficulty:'medium', category:'raiva', theme:'letalidade', q:"A raiva em humanos, uma vez com sintomas neurológicos instalados, é:", alt:["Curável com remédios caseiros","Quase sempre fatal (~100% de letalidade)","Leve e autolimitada","Doença autoimune tratável"], c:1, e:"Quando sintomas aparecem, dano neurológico é irreversível. Profilaxia pós-exposição deve ser imediata."},
    {id:63, stage:2, difficulty:'medium', category:'classificação', theme:'virose', q:"Qual das seguintes NÃO é uma virose (doença viral)?", alt:["Sarampo (paramixovírus)","Tétano (Clostridium tetani - bactéria)","Hepatite A (picornavírus)","HPV (papilomavírus)"], c:1, e:"Tétano é bacteriano. Antibióticos não funcionam contra as outras, que exigem prevenção vacinal."},
    {id:64, stage:2, difficulty:'hard', category:'vetores', theme:'albopictus', q:"Sobre o Aedes albopictus, é correto afirmar:", alt:["Não transmite nenhum vírus humano","Pode transmitir dengue, vive em matas e periferias, é mais resistente ao frio","É sempre menor que o Aedes aegypti","Só bebe água doce de nascentes"], c:1, e:"Vetor secundário importante, adaptado a diferentes climas. Expansão geográfica preocupa autoridades."},
    {id:65, stage:2, difficulty:'hard', category:'vacinas', theme:'febre_amarela', q:"A vacina da febre amarela:", alt:["Precisa de reforço anual como a da gripe","É dose única com proteção vitalícia para a maioria","Causa febre em 100% dos vacinados","Não protege contra a forma silvestre"], c:1, e:"Uma dose confere imunidade duradoura. Certificado Internacional de Vacinação válido por vida desde 2016."},
    {id:66, stage:2, difficulty:'hard', category:'chikungunya', theme:'sequelas', q:"Chikungunya pode causar como complicação crônica:", alt:["Morte em 24 horas sem tratamento","Artrite e dores articulares persistentes por meses ou anos","Paralisia flácida aguda","Cegueira súbita bilateral"], c:1, e:"Dores articulares incapacitantes podem persistir, exigindo reabilitação e manejo da dor a longo prazo."},
    {id:67, stage:2, difficulty:'hard', category:'pneumonia', theme:'diferencial', q:"Diferença crucial entre pneumonia viral e bacteriana:", alt:["Sempre tratada com o mesmo antibiótico","Pneumonia viral não responde a antibióticos; uso inadequado gera resistência","São clinicamente indistinguíveis e tratadas igual","Pneumonia viral só ocorre em idosos"], c:1, e:"Diagnóstico correto evita prescrição desnecessária de antibióticos, combatendo resistência bacteriana."},
    {id:68, stage:2, difficulty:'hard', category:'covid19', theme:'fômites', q:"A transmissão da covid-19 por superfícies (fômites) é considerada:", alt:["A principal via de disseminação","Rara ou possível, mas não dominante; aerossóis são mais relevantes","Impossível fisicamente","Só ocorre em superfícies metálicas"], c:1, e:"Via secundária. Higiene das mãos é importante, mas foco deve ser ventilação e máscara em ambientes fechados."},
    {id:69, stage:2, difficulty:'hard', category:'gripe', theme:'classificação', q:"O vírus da gripe (Influenza) é classificado por:", alt:["Tamanho das partículas virais","Hemaglutinina (H) e Neuraminidase (N) - ex: H1N1","Cor das colônias em cultura","País de origem do primeiro caso"], c:1, e:"Proteínas de superfície definem subtipos. Mutações nessas proteínas exigem atualização vacinal anual."},
    {id:70, stage:2, difficulty:'hard', category:'dengue', theme:'comportamento', q:"O Aedes aegypti tem hábitos de picada preferencialmente:", alt:["Exclusivamente noturnos","Diurnos, com picos ao amanhecer e entardecer, mas pode picar à noite","Apenas em florestas densas","Só em ambientes com ar condicionado"], c:1, e:"Adaptado ao ambiente urbano. Repelentes e roupas claras/compridas ajudam na proteção diurna."},
    {id:71, stage:2, difficulty:'hard', category:'hpv', theme:'oncogênico', q:"O HPV (papilomavírus humano) está associado principalmente a:", alt:["Gripe sazonal com complicações","Câncer de colo do útero, pênis, ânus e orofaringe","Dengue com manifestações hemorrágicas","Tétano generalizado"], c:1, e:"Vacina previne tipos oncogênicos. Recomendada para meninas (9-14 anos) e meninos (11-14 anos) pelo SUS."},
    {id:72, stage:2, difficulty:'hard', category:'catapora', theme:'reativação', q:"A varicela (catapora) no adulto pode reativar anos depois como:", alt:["Caxumba com parotidite","Herpes zóster (cobreiro) com dor neural","Gripe com pneumonia viral","Febre tifoide"], c:1, e:"Vírus fica latente em gânglios nervosos. Reativação causa zóster, mais comum em idosos ou imunodeprimidos."},
    {id:73, stage:2, difficulty:'hard', category:'sarampo', theme:'contagiosidade', q:"O sarampo é altamente contagioso porque:", alt:["Só se pega com toque direto na pele","O vírus pode ficar no ar por até 2 horas após pessoa infectada sair do local","Só se transmite por sangue contaminado","Só ocorre em ambientes escolares"], c:1, e:"R0 muito alto (12-18). Suscetíveis não vacinados têm ~90% de risco de infecção após exposição."},
    {id:74, stage:2, difficulty:'easy', category:'raiva', theme:'sintoma', q:"Qual doença causa 'hidrofobia' como sintoma característico?", alt:["Cólera com desidratação","Raiva com espasmos faríngeos","Dengue com dores articulares","Malária com calafrios"], c:1, e:"Medo/espasmo ao tentar engolir água. Sinal neurológico grave da raiva em fase sintomática."},
    {id:75, stage:2, difficulty:'easy', category:'transmissão', theme:'aerossol', q:"O que é 'aerossol' na transmissão de vírus respiratórios?", alt:["Gota grande que cai rápido no chão","Partículas minúsculas que ficam suspensas no ar por minutos/horas","Poeira doméstica comum","Água parada em recipientes"], c:1, e:"Permanece no ar, especialmente em ambientes fechados e mal ventilados. Máscara e ventilação são barreiras."},
    {id:76, stage:2, difficulty:'easy', category:'febre_amarela', theme:'urbana', q:"A febre amarela urbana depende da presença de qual vetor?", alt:["Aedes aegypti","Barbeiro (Triatoma)","Caramujo (Biomphalaria)","Pulga (Xenopsylla)"], c:0, e:"Retorno à cidade: humano infectado na mata + Aedes urbano = risco de surto urbano. Vacinação é barreira."},
    {id:77, stage:2, difficulty:'medium', category:'poliomielite', theme:'sintomas', q:"A poliomielite NÃO causa tipicamente:", alt:["Febre e mal-estar inicial","Paralisia flácida assimétrica","Diarreia intensa constante como sintoma principal","Esterilidade ou infertilidade"], c:3, e:"Atinge sistema nervoso central e músculos. Não afeta órgãos reprodutivos diretamente."},
    {id:78, stage:2, difficulty:'medium', category:'zika', theme:'diagnóstico', q:"Zika vírus pode ser detectado por:", alt:["PCR (fase aguda), exame clínico e sorologia (fase tardia)","Apenas raio-X de tórax","Só exame de fezes","Apenas palpação de gânglios"], c:0, e:"Diagnóstico clínico-laboratorial. PCR em sangue/urina na 1ª semana; sorologia depois para anticorpos."},
    {id:79, stage:2, difficulty:'medium', category:'arboviroses', theme:'comum', q:"Dengue, Zika e Chikungunya compartilham:", alt:["O mesmo vírus causador","O mesmo vetor principal (Aedes aegypti) e medidas de prevenção","O mesmo tratamento antiviral específico","Acometem apenas crianças"], c:1, e:"Controle integrado do vetor beneficia prevenção das três. Não há antiviral específico; tratamento é sintomático."},
    {id:80, stage:2, difficulty:'medium', category:'vacinas', theme:'tríplice', q:"A vacina tríplice viral protege contra:", alt:["Sarampo, Caxumba e Rubéola","Gripe, Dengue e Zika","Tétano, Difteria e Coqueluche","HPV, Hepatite B e A"], c:0, e:"Calendário infantil: 1ª dose aos 12 meses, reforço aos 15 meses. Essencial para controle dessas viroses."},
    
    // ETAPA 3: Doenças Bacterianas + Saneamento (35 questões)
    {id:81, stage:3, difficulty:'easy', category:'leptospirose', theme:'transmissão', q:"Leptospirose é transmitida principalmente por:", alt:["Picada de mosquito Aedes","Contato com água/lama contaminada por urina de ratos","Inalação de ar condicionado","Comida queimada ou estragada"], c:1, e:"Bactéria Leptospira entra por pele/mucosa lesada. Enchentes aumentam risco. Prevenção: evitar contato com água de alagamento."},
    {id:82, stage:3, difficulty:'easy', category:'cólera', theme:'sintoma', q:"Cólera causa principalmente:", alt:["Tosse produtiva com catarro","Diarreia aquosa intensa tipo 'água de arroz'","Dor de cabeça latejante","Manchas vermelhas na pele"], c:1, e:"Perda rápida de água e eletrólitos. Risco de desidratação severa e choque hipovolêmico em horas."},
    {id:83, stage:3, difficulty:'easy', category:'tuberculose', theme:'alvo', q:"Tuberculose afeta principalmente qual órgão?", alt:["Fígado e vesícula biliar","Pulmões (forma pulmonar é a mais comum)","Coração e válvulas","Pele e unhas"], c:1, e:"Bacilo de Koch (Mycobacterium tuberculosis). Tosse >3 semanas é sinal de alerta. BCG previne formas graves."},
    {id:84, stage:3, difficulty:'easy', category:'tétano', theme:'entrada', q:"Tétano entra no corpo principalmente por:", alt:["Inalação de esporos no ar","Ferimentos na pele contaminados com solo/objetos","Picada de mosquito vetor","Água potável não clorada"], c:1, e:"Esporos de Clostridium tetani no solo entram em cortes profundos. Anaerobiose favorece germinação e produção de toxina."},
    {id:85, stage:3, difficulty:'easy', category:'hanseníase', theme:'agente', q:"Hanseníase é causada por:", alt:["Vírus da família Herpes","Bactéria Mycobacterium leprae","Fungo dermatófito","Protozoário flagelado"], c:1, e:"Doença negligenciada, tem tratamento gratuito e cura pelo SUS. Estigma é maior barreira que a doença."},
    {id:86, stage:3, difficulty:'easy', category:'saneamento', theme:'definição', q:"Saneamento básico inclui:", alt:["Apenas coleta de lixo domiciliar","Água tratada, rede de esgoto e drenagem urbana","Só construção de hospitais","Vacinação em massa"], c:1, e:"Infraestrutura que previne múltiplas doenças de veiculação hídrica e vetorial. Direito humano fundamental."},
    {id:87, stage:3, difficulty:'medium', category:'leptospirose', theme:'enchente', q:"Enchentes aumentam risco principalmente de:", alt:["Gripe sazonal","Leptospirose por contato com água contaminada","Catapora em crianças","Zika por mosquito"], c:1, e:"Alagamento mistura esgoto e urina de ratos. Botas, luvas e evitar contato são medidas de proteção."},
    {id:88, stage:3, difficulty:'medium', category:'cólera', theme:'prevenção', q:"Cólera se previne principalmente com:", alt:["Higiene de alimentos e água (cloração, cozimento)","Vacina BCG no braço","Isolamento social rigoroso","Antibiótico profilático para toda a população"], c:0, e:"Cloração da água, cozimento de alimentos, lavar mãos e vegetais. Saneamento é prevenção estrutural."},
    {id:89, stage:3, difficulty:'medium', category:'vacinas', theme:'bcg', q:"A vacina BCG protege principalmente contra:", alt:["Tétano generalizado","Formas graves de tuberculose (meningite, miliar)","Dengue hemorrágica","Cólera desidratante"], c:1, e:"Aplicada no braço ao nascer, deixa cicatriz característica. Não previne infecção, mas formas disseminadas."},
    {id:90, stage:3, difficulty:'medium', category:'tétano', theme:'sintoma', q:"Tétano causa como sintoma característico:", alt:["Diarreia aquosa intensa","Rigidez muscular e espasmos dolorosos (trismo, opistótono)","Tosse com catarro verde","Febre baixa persistente"], c:1, e:"Toxina tetanospasmina bloqueia inibição neural → contrações musculares sustentadas. Prevenção: vacinação + limpeza de feridas."},
    {id:91, stage:3, difficulty:'medium', category:'hanseníase', theme:'transmissão', q:"Hanseníase se transmite principalmente por:", alt:["Picada de inseto vetor","Contato prolongado/inalação de secreções respiratórias de doente não tratado","Água de piscina contaminada","Relação sexual desprotegida"], c:1, e:"Incubação longa (2-7 anos). 90% das pessoas são naturalmente resistentes. Tratamento interrompe transmissão."},
    {id:92, stage:3, difficulty:'medium', category:'saneamento', theme:'impacto', q:"Saneamento precário favorece principalmente:", alt:["Doenças crônicas não transmissíveis","Doenças de veiculação hídrica (cólera, hepatite A, diarreias)","Câncer de pele por exposição solar","Alergias respiratórias sazonais"], c:1, e:"Ciclo fecal-oral ativo: patógenos de fezes humanas contaminam água/alimentos. Saneamento quebra esse ciclo."},
    {id:93, stage:3, difficulty:'medium', category:'água', theme:'tratamento', q:"Água tratada para consumo passa por processos como:", alt:["Apenas fervura caseira","Cloração, filtração e floculação em ETA","Nada, é naturalmente pura","Apenas fervura solar em garrafas PET"], c:1, e:"Estações de Tratamento garantem segurança microbiológica. Cloro residual protege na rede de distribuição."},
    {id:94, stage:3, difficulty:'medium', category:'esgoto', theme:'contaminação', q:"Esgoto sem tratamento contamina principalmente:", alt:["Apenas o ar atmosférico","Solo e mananciais de água (rios, lençol freático)","Rochas e minerais","Nuvens e precipitação"], c:1, e:"Retorna ao ciclo hidrológico carregando patógenos e nutrientes que causam eutrofização."},
    {id:95, stage:3, difficulty:'medium', category:'lixo', theme:'vetores', q:"Lixo a céu aberto atrai principalmente:", alt:["Vacas e cavalos","Ratos, baratas e moscas que são vetores/reservatórios","Pássaros raros protegidos","Peixes de água doce"], c:1, e:"Aumenta risco de leptospirose (ratos), doenças transmitidas por alimentos (moscas) e alergias (baratas)."},
    {id:96, stage:3, difficulty:'medium', category:'pneumonia', theme:'tratamento', q:"Pneumonia bacteriana é tratada com:", alt:["Antiviral específico","Antibiótico prescrito conforme agente suspeito","Soro antitetânico","Antifúngico de amplo espectro"], c:1, e:"Diagnóstico clínico + exames orienta escolha do antibiótico. Completa o curso mesmo com melhora dos sintomas."},
    {id:97, stage:3, difficulty:'medium', category:'fossa', theme:'alternativa', q:"Fossa séptica evita principalmente:", alt:["Doenças transmitidas pelo ar","Contaminação do lençol freático por dejetos humanos","Alergias a ácaros","Ruído urbano"], c:1, e:"Trata dejetos onde não há rede de esgoto. Deve ser impermeável e distante de poços para não contaminar água."},
    {id:98, stage:3, difficulty:'medium', category:'higiene', theme:'hipoclorito', q:"Higienizar alimentos com solução de hipoclorito de sódio:", alt:["É inútil e desperdício","Elimina bactérias e vírus superficiais","Mancha todos os vegetais de azul","Causa câncer se usado corretamente"], c:1, e:"Cloro ativo mata patógenos. Seguir diluição e tempo do rótulo. Enxaguar após para remover resíduos."},
    {id:99, stage:3, difficulty:'medium', category:'cólera', theme:'agente', q:"A bactéria causadora da cólera é:", alt:["Vibrio cholerae","Mycobacterium tuberculosis (bacilo de Koch)","Treponema pallidum (sífilis)","Staphylococcus aureus"], c:0, e:"Vibrio cholerae produz toxina que causa secreção intestinal massiva. Epidemias históricas moldaram saúde pública."},
    {id:100, stage:3, difficulty:'medium', category:'tétano', theme:'neonatal', q:"O tétano neonatal ocorre principalmente por:", alt:["Corte do cordão umbilical com instrumento não esterilizado","Picada de mosquito em recém-nascido","Ar condicionado no berçário","Leite materno contaminado"], c:0, e:"Prática insegura em partos domiciliares sem higiene. Previna com parto hospitalar e vacinação materna."},
    {id:101, stage:3, difficulty:'medium', category:'hanseníase', theme:'cura', q:"Hanseníase tem cura?", alt:["Não, é doença crônica incurável","Sim, com poliquimioterapia (PQT) gratuita pelo SUS","Só com cirurgia plástica reconstrutiva","Só com repouso absoluto"], c:1, e:"Tratamento longo (6-12 meses), mas eficaz. Isolamento é desnecessário; paciente tratado não transmite."},
    {id:102, stage:3, difficulty:'medium', category:'diarreia', theme:'risco', q:"A diarreia por bactéria pode matar principalmente por:", alt:["Dor abdominal intensa","Desidratação e perda de eletrólitos","Febre alta persistente","Tosse produtiva"], c:1, e:"Perda rápida de água/sais. Soro de reidratação oral (SRO) é intervenção que salva vidas, especialmente em crianças."},
    {id:103, stage:3, difficulty:'medium', category:'saneamento', theme:'direito', q:"Saneamento básico é considerado:", alt:["Luxo para países ricos","Direito humano fundamental","Opção para áreas urbanas","Só necessário em cidades grandes"], c:1, e:"Reconhecido pela ONU. Essencial para saúde, dignidade e desenvolvimento sustentável."},
    {id:104, stage:3, difficulty:'hard', category:'leptospirose', theme:'entrada', q:"A leptospirose entra no corpo principalmente pela:", alt:["Inalação de ar seco","Pele/mucosa em contato com água contaminada (lesões microscópicas, conjuntiva)","Picada de inseto","Comida crua bem lavada"], c:1, e:"Bactéria penetra por pequenas lesões ou mucosas. Botas e luvas são EPIs importantes em enchentes."},
    {id:105, stage:3, difficulty:'hard', category:'tuberculose', theme:'notificação', q:"A tuberculose é de notificação:", alt:["Opcional para médicos","Compulsória imediata à vigilância epidemiológica","Só em hospitais privados","Só para infectologistas"], c:1, e:"Doença de notificação compulsória. Vigilância ativa permite rastrear contatos e interromper transmissão."},
    {id:106, stage:3, difficulty:'hard', category:'soro', theme:'antitetânico', q:"O soro antitetânico é dado quando:", alt:["Carteira de vacinação está em dia","Há ferimento de risco + vacinação incerta/defasada (imunização passiva + ativa)","Para prevenir gripe sazonal","No tratamento da cólera desidratante"], c:1, e:"Anticorpos prontos neutralizam toxina já produzida. Vacina simultânea estimula produção própria para proteção duradoura."},
    {id:107, stage:3, difficulty:'hard', category:'resistência', theme:'causa', q:"A resistência bacteriana a antibióticos surge principalmente por:", alt:["Uso indevido/excesso de antibióticos (seleção natural de cepas resistentes)","Vacinação em massa","Higiene excessiva","Saneamento básico"], c:0, e:"Pressão seletiva: bactérias sensíveis morrem, resistentes sobrevivem e se multiplicam. Uso racional é crucial."},
    {id:108, stage:3, difficulty:'hard', category:'esgoto', theme:'impacto', q:"Falta de rede de esgoto aumenta principalmente:", alt:["Índice pluviométrico anual","Carga de patógenos no ambiente e risco de doenças","Ruído urbano noturno","Trânsito de veículos"], c:1, e:"Excrementos humanos no ambiente = risco sanitário. Saneamento é investimento em saúde preventiva."},
    {id:109, stage:3, difficulty:'hard', category:'hanseníase', theme:'alvo', q:"Hanseníase ataca principalmente:", alt:["Fígado e vesícula","Pele e nervos periféricos (perda de sensibilidade)","Pulmões e brônquios","Rins e bexiga"], c:1, e:"Lesões cutâneas anestésicas, deformidades por lesão nervosa. Diagnóstico precoce evita incapacidades."},
    {id:110, stage:3, difficulty:'hard', category:'tétano', theme:'ecologia', q:"A bactéria do tétano (Clostridium tetani) vive naturalmente no:", alt:["Ar puro atmosférico","Solo e intestino de animais (forma esporulada resistente)","Água doce de rios","Sangue humano"], c:1, e:"Esporos são ubíquos no ambiente. Ferimentos profundos com necrose criam anaerobiose para germinação."},
    {id:111, stage:3, difficulty:'hard', category:'economia', theme:'custo_benefício', q:"Investir R$1 em saneamento economiza ~R$9 em saúde porque:", alt:["Saneamento é caro e ineficiente","Previne custos de internação, afastamento e perda de produtividade","Não economiza, é gasto puro","Só melhora estética urbana"], c:1, e:"Prevenção é mais barata que tratamento de crises. Saneamento gera retorno econômico e social."},
    {id:112, stage:3, difficulty:'hard', category:'hanseníase', theme:'contato', q:"A transmissão da hanseníase requer:", alt:["Toque rápido e casual","Contato próximo e prolongado com doente não tratado","Só relação sexual","Transmissão aérea rápida como gripe"], c:1, e:"Exposição repetida necessária. 95% da população é naturalmente imune. Tratamento interrompe transmissão em dias."},
    {id:113, stage:3, difficulty:'hard', category:'cólera', theme:'epidemiologia', q:"A cólera é mais comum em:", alt:["Locais com água potável tratada","Áreas de desastre, conflito ou saneamento precário","Montanhas geladas","Desertos sem população"], c:1, e:"Enchentes, guerras, falta de infraestrutura. Resposta rápida com água segura e SRO salva vidas."},
    {id:114, stage:3, difficulty:'hard', category:'tuberculose', theme:'tratamento', q:"A tuberculose tem tratamento com:", alt:["Antibióticos por 6 meses (esquema RIPE)","Vacina anual como a da gripe","Soro antitetânico","Cirurgia pulmonar de rotina"], c:0, e:"Rifampicina, Isoniazida, Pirazinamida, Etambutol. Adesão completa evita resistência e recaída."},
    {id:115, stage:3, difficulty:'hard', category:'leptospirose', theme:'reservatório', q:"O controle de ratos previne principalmente:", alt:["Dengue por Aedes","Leptospirose (rato é reservatório da Leptospira)","Gripe sazonal","Malária por Anopheles"], c:1, e:"Rato assintomático elimina bactéria na urina. Saneamento, lixo adequado e desratização são estratégias."},
    
    // ETAPA 4: Revisão Final + Interpretação (35 questões)
    {id:116, stage:4, difficulty:'easy', category:'antibióticos', theme:'especificidade', q:"Antibiótico cura gripe?", alt:["Sim, sempre","Não, gripe é viral e antibióticos só atuam em bactérias","Às vezes, depende da cepa","Só em crianças abaixo de 5 anos"], c:1, e:"Uso inadequado de antibióticos em viroses é ineficaz e contribui para resistência bacteriana."},
    {id:117, stage:4, difficulty:'easy', category:'febre_amarela', theme:'mito', q:"Macacos transmitem febre amarela para humanos?", alt:["Sim, por mordida","Não, são vítimas/sentinels; transmissão é por mosquito","Só bugios transmitem","Só saguis transmitem"], c:1, e:"Macacos adoecem e morrem. Sua morte alerta para circulação viral. Matar macacos prejudica vigilância."},
    {id:118, stage:4, difficulty:'easy', category:'higiene', theme:'mãos', q:"Lavar as mãos com água e sabão previne:", alt:["Só gripe","Várias doenças (diarreias, respiratórias, pele)","Nenhuma doença, é mito","Apenas alergias"], c:1, e:"Remove patógenos de contato. Medida simples, barata e eficaz. Momentos-chave: antes de comer, após banheiro."},
    {id:119, stage:4, difficulty:'easy', category:'dengue', theme:'criadouro', q:"Água parada em recipientes favorece:", alt:["Tuberculose pulmonar","Reprodução do mosquito Aedes aegypti","Hanseníase","Cólera intestinal"], c:1, e:"Eliminação semanal de água parada é a principal medida de controle de arboviroses urbanas."},
    {id:120, stage:4, difficulty:'easy', category:'fake_news', theme:'característica', q:"Fake news geralmente:", alt:["Cita fontes científicas e dados verificáveis","Usa sensacionalismo, medo e urgência para viralizar","É técnica e detalhada","É lenta para se espalhar"], c:1, e:"Apelo emocional > evidência. Checar fonte, data, autoria e consenso científico antes de compartilhar."},
    {id:121, stage:4, difficulty:'medium', category:'interpretação', theme:'cenário', q:"Se uma região tem alta incidência de dengue e baixa de cólera, o problema sanitário principal é:", alt:["Só falta de água potável","Vetor urbano (água parada domiciliar) + saneamento relativo para água de ingestão","Só clima tropical","Só pobreza"], c:1, e:"Dengue: Aedes em criadouros domiciliares. Cólera: água de ingestão contaminada. Prevenções são complementares."},
    {id:122, stage:4, difficulty:'medium', category:'prevenção', theme:'zoonose', q:"Vacinar animais de estimação previne principalmente:", alt:["Dengue urbana","Raiva (quebra ciclo zoonótico)","Cólera hídrica","Malária por mosquito"], c:1, e:"Saúde única: saúde humana, animal e ambiental interligadas. Vacinação animal é estratégia de saúde pública."},
    {id:123, stage:4, difficulty:'medium', category:'leptospirose', theme:'prevenção', q:"Qual medida NÃO previne leptospirose diretamente?", alt:["Eliminar água parada (previne Aedes, não leptospirose)","Usar calçados e luvas em enchentes","Controle de ratos e saneamento","Evitar contato com água de alagamento"], c:0, e:"Água parada atrai Aedes (dengue). Leptospirose: urina de rato em água/lama. Medidas são diferentes."},
    {id:124, stage:4, difficulty:'medium', category:'epidemiologia', theme:'diferença', q:"O que diferencia epidemia de endemia?", alt:["Duração/padrão temporal e geográfico","Agente causador específico","Tratamento disponível","Faixa etária acometida"], c:0, e:"Epidemia: surto repentino. Endemia: presença constante. Pandemia: disseminação global."},
    {id:125, stage:4, difficulty:'medium', category:'soro', theme:'indicação', q:"Soro é indicado quando:", alt:["Precisa de proteção futura (prevenção)","Já há exposição/contágio e necessidade de ação imediata","Para gripe leve autolimitada","Para vacinar contra doenças"], c:1, e:"Imunização passiva emergencial. Anticorpos prontos neutralizam toxina/vírus já no organismo."},
    {id:126, stage:4, difficulty:'medium', category:'febre_amarela', theme:'sentinel', q:"Por que macacos morrem de febre amarela?", alt:["São imunes e não adoecem","São sensíveis como humanos; morte alerta para circulação viral","São vetores biológicos ativos","Comem mosquitos e intoxicam"], c:1, e:"Sentinelas epidemiológicas. Investigação de mortandade orienta vacinação de humanos em áreas de risco."},
    {id:127, stage:4, difficulty:'medium', category:'saneamento', theme:'impacto', q:"Qual afirmação sobre saneamento é correta?", alt:["Só evita doenças bacterianas","Evita múltiplas doenças (bacterianas, virais, parasitárias) e melhora indicadores econômicos","Só é necessário em cidades grandes","Não afeta saúde, só estética"], c:1, e:"Base da saúde pública. Reduz mortalidade infantil, melhora produtividade e qualidade de vida."},
    {id:128, stage:4, difficulty:'medium', category:'vetores', theme:'especificidade', q:"Aedes aegypti NÃO transmite:", alt:["Dengue","Zika","Malária (transmitida por Anopheles)","Chikungunya"], c:2, e:"Malária: vetor é mosquito Anopheles. Cada doença tem vetor/especificidade. Controle deve ser direcionado."},
    {id:129, stage:4, difficulty:'medium', category:'higiene', theme:'vinagre', q:"Higienizar alimentos com vinagre:", alt:["É tão eficaz quanto cloro contra patógenos","Remove sujeira, mas é menos eficaz contra microrganismos que cloro ativo","Causa intoxicação alimentar","É proibido pela Anvisa"], c:1, e:"Vinagre tem ação limitada. Hipoclorito de sódio (cloro) é mais eficaz para desinfecção de vegetais."},
    {id:130, stage:4, difficulty:'medium', category:'vacinas', theme:'especificidade', q:"Vacina tríplice viral NÃO protege contra:", alt:["Caxumba","Sarampo","Rubéola","Dengue (tem vacina específica quando indicada)"], c:3, e:"Tríplice viral: sarampo, caxumba, rubéola. Dengue tem vacina própria (indicada em situações específicas)."},
    {id:131, stage:4, difficulty:'hard', category:'interpretação', theme:'saneamento_incompleto', q:"Se um bairro tem água tratada mas esgoto a céu aberto, espera-se maior incidência de:", alt:["Zero doenças transmissíveis","Diarreias e parasitoses por ciclo fecal-oral","Dengue por Aedes","Gripe por influenza"], c:1, e:"Esgoto a céu aberto contamina solo/água. Mesmo com água tratada, higiene e saneamento completos são necessários."},
    {id:132, stage:4, difficulty:'hard', category:'vacinas', theme:'coletivo', q:"Por que a vacinação é uma estratégia coletiva, não apenas individual?", alt:["Só protege o vacinado","Reduz circulação do patógeno, protegendo indiretamente quem não pode se vacinar","Gera lucro para indústria farmacêutica","É obrigatória por lei, sem base científica"], c:1, e:"Imunidade de rebanho: barreira epidemiológica que protege imunodeprimidos, alérgicos e bebês."},
    {id:133, stage:4, difficulty:'hard', category:'saúde_pública', theme:'lockdown', q:"Qual cenário indica necessidade de medidas restritivas como lockdown?", alt:["Poucos casos esporádicos","Colapso iminente do sistema de saúde (UTI lotadas)","Período de férias escolares","Previsão de chuva intensa"], c:1, e:"Medida extrema para ganhar tempo: ampliar leitos, equipamentos, vacinação e evitar mortes evitáveis."},
    {id:134, stage:4, difficulty:'hard', category:'dengue', theme:'adaptação', q:"Aedes aegypti se adapta principalmente a:", alt:["Só florestas tropicais","Ambiente urbano e doméstico (peridomicílio)","Apenas climas frios","Apenas calor extremo sem água"], c:1, e:"Pneus, vasos, calhas, caixas d'água. Controle depende da ação comunitária semanal de eliminação de criadouros."},
    {id:135, stage:4, difficulty:'hard', category:'fake_news', theme:'impacto', q:"Fake news sobre saúde prejudica principalmente:", alt:["Só o autor da mensagem","A adesão a campanhas de prevenção e a saúde pública como um todo","Ninguém, é inofensiva","A economia, sem afetar saúde"], c:1, e:"Desinformação reduz cobertura vacinal, aumenta casos evitáveis e custa vidas e recursos do sistema."},
    {id:136, stage:4, difficulty:'hard', category:'prevenção', theme:'integrada', q:"Qual combinação previne simultaneamente cólera E leptospirose?", alt:["Só vacina específica para cada","Saneamento + higiene + controle de ratos/enchentes","Só uso de máscara","Só ar condicionado"], c:1, e:"Medidas estruturais (saneamento) e comportamentais (higiene, EPIs em enchentes) integradas são mais eficazes."},
    {id:137, stage:4, difficulty:'hard', category:'imunidade', theme:'rebanho', q:"O que é 'imunidade de rebanho'?", alt:["Vacas vacinadas contra febre aftosa","Proteção indireta quando % suficiente da população está imune, reduzindo transmissão","Doença de gado","Vacina cara para ricos"], c:1, e:"Conceito epidemiológico: interrupção da cadeia de transmissão protege quem não desenvolveu imunidade."},
    {id:138, stage:4, difficulty:'hard', category:'interpretação', theme:'erro_conceitual', q:"Se um aluno diz 'antibiótico cura dengue', ele:", alt:["Está correto","Confunde agente causal (dengue é viral, antibiótico só atua em bactérias)","Só está errado para adultos","Só está errado em hospitais"], c:1, e:"Erro conceitual grave. Antibióticos não atuam contra vírus. Uso inadequado gera resistência bacteriana."},
    {id:139, stage:4, difficulty:'hard', category:'fake_news', theme:'checagem', q:"Qual é a melhor forma de evitar cair em fake news sobre saúde?", alt:["Compartilhar sem ler para alertar outros","Verificar fonte oficial (SUS, Fiocruz, OMS), data, autoria e consenso científico","Acreditar em áudios de WhatsApp","Ignorar ciência e seguir 'intuição'"], c:1, e:"Checagem de fatos: agências como Lupa, Aos Fatos, e fontes oficiais são essenciais na era da desinformação."},
    {id:140, stage:4, difficulty:'hard', category:'saneamento', theme:'determinante', q:"O saneamento básico é a base para:", alt:["Aumento de doenças transmissíveis","Prevenção primária de doenças e desenvolvimento sustentável","Poluição ambiental intencional","Isolamento social permanente"], c:1, e:"Determinante social de saúde. Acesso universal a saneamento é meta dos ODS (Objetivos de Desenvolvimento Sustentável)."},
    {id:141, stage:4, difficulty:'easy', category:'conceitos', theme:'revisão', q:"Qual a principal diferença entre vacina e soro?", alt:["Vacina é oral, soro é injetável","Vacina previne (estimula anticorpos), soro trata (fornece anticorpos prontos)","Vacina é cara, soro é gratuito","Vacina é para vírus, soro para bactérias"], c:1, e:"Memorize: 'Vacina previne; soro socorre'. Ação preventiva vs terapêutica emergencial."},
    {id:142, stage:4, difficulty:'easy', category:'vetores', theme:'revisão', q:"Qual mosquito transmite dengue, Zika e chikungunya?", alt:["Anopheles","Aedes aegypti","Culex","Lutzomyia"], c:1, e:"Aedes aegypti: vetor urbano das três arboviroses. Controle: eliminar água parada semanalmente."},
    {id:143, stage:4, difficulty:'easy', category:'bactérias', theme:'revisão', q:"Qual bactéria causa tétano?", alt:["Vibrio cholerae","Clostridium tetani","Mycobacterium leprae","Salmonella typhi"], c:1, e:"Clostridium tetani: anaeróbio, produz toxina neural. Prevenção: vacinação + limpeza de ferimentos."},
    {id:144, stage:4, difficulty:'easy', category:'prevenção', theme:'revisão', q:"Qual medida previne leptospirose em enchentes?", alt:["Usar máscara N95","Evitar contato com água/lama + usar EPIs (botas, luvas)","Tomar antibiótico preventivo","Ficar em casa sem sair"], c:1, e:"Proteção individual: evitar contato com água de alagamento. Se necessário, usar equipamentos de proteção."},
    {id:145, stage:4, difficulty:'medium', category:'interpretação', theme:'cenário_complexo', q:"Uma comunidade com água tratada, mas sem coleta de lixo e esgoto, terá maior risco de:", alt:["Dengue e leptospirose (lixo atrai ratos, esgoto contamina)","Só doenças respiratórias","Só doenças de pele","Zero risco de doenças"], c:0, e:"Saneamento incompleto: água tratada previne cólera, mas lixo/esgoto favorecem leptospirose e outras."},
    {id:146, stage:4, difficulty:'medium', category:'vacinas', theme:'memória', q:"Por que algumas vacinas precisam de reforço?", alt:["Porque o sistema imune 'esquece' o patógeno com o tempo","Para manter níveis protetores de anticorpos e memória imunológica","Porque a vacina original era defeituosa","Para testar nova tecnologia"], c:1, e:"Imunidade pode declinar. Reforços reestimulam memória imunológica para proteção duradoura."},
    {id:147, stage:4, difficulty:'medium', category:'epidemiologia', theme:'indicadores', q:"Se uma doença tem R0 > 1, isso significa que:", alt:["Cada doente infecta, em média, mais de uma pessoa → epidemia cresce","A doença está em declínio","A vacina é 100% eficaz","Não há transmissão"], c:0, e:"R0 (número básico de reprodução): >1 = crescimento, <1 = declínio. Meta de intervenções: reduzir R0 <1."},
    {id:148, stage:4, difficulty:'medium', category:'prevenção', theme:'camadas', q:"A estratégia de 'camadas de proteção' (máscara + distância + vacina + ventilação) é eficaz porque:", alt:["Nenhuma medida é 100%, mas juntas reduzem risco drasticamente","É mais barata que uma única medida","Substitui a necessidade de profissionais de saúde","É obrigatória por lei"], c:0, e:"Analogia do 'queijo suíço': cada camada tem 'furos', mas sobrepostas bloqueiam a transmissão."},
    {id:149, stage:4, difficulty:'hard', category:'interpretação', theme:'análise_crítica', q:"Ao analisar uma notícia sobre saúde, qual pergunta NÃO é essencial?", alt:["Qual é a fonte? É confiável?","Quem é o autor? Tem qualificação?","Qual a data? Está atualizada?","Qual é a cor da fonte no site?"], c:3, e:"Checagem crítica: fonte, autoria, data, evidências, consenso. Estética do site não garante confiabilidade."},
    {id:150, stage:4, difficulty:'hard', category:'síntese', theme:'prevenção_coletiva', q:"Qual combinação de medidas tem maior impacto na prevenção de doenças transmissíveis em uma comunidade?", alt:["Só vacinação em massa","Só saneamento básico","Vacinação + saneamento + higiene + educação em saúde","Só tratamento hospitalar de doentes"], c:2, e:"Abordagem integrada: prevenção primária (saneamento, higiene), secundária (vacinas) e terciária (tratamento)."},
    
    // QUESTÕES DO SIMULADO OFICIAL (50 questões fornecidas - mapeadas para etapas)
    // Parte 4 do simulado (questões 41-50) - Etapa 4
    {id:151, stage:4, difficulty:'medium', category:'interpretação', theme:'leptospirose_enchente', q:"Após fortes chuvas e enchentes, aumentaram casos de febre, dores musculares e infecções por contato com água contaminada por urina de ratos. A doença mais associada é:", alt:["Dengue","Covid-19","Leptospirose","Sarampo","Catapora"], c:2, e:"Leptospirose: transmissão por água/lama com urina de roedores. Comum em enchentes. Prevenção: evitar contato, usar EPIs."},
    {id:152, stage:4, difficulty:'easy', category:'epidemiologia', theme:'epidemia', q:"Uma cidade apresentou aumento rápido de casos de dengue durante alguns meses, mas apenas naquela região. Isso caracteriza:", alt:["Pandemia","Mutação","Endemia mundial","Epidemia","Imunização"], c:3, e:"Epidemia: aumento repentino de casos em área geográfica delimitada. Pandemia seria disseminação global."},
    {id:153, stage:4, difficulty:'easy', category:'dengue', theme:'prevenção_vetor', q:"Agentes de saúde orientam eliminar recipientes com água parada para combater dengue. Isso é importante porque:", alt:["Elimina diretamente o vírus da dengue","Impede a reprodução do mosquito vetor","Mata bactérias da água","Substitui as vacinas","Reduz poluição do ar"], c:1, e:"Aedes aegypti põe ovos em água parada. Eliminar criadouros interrompe ciclo reprodutivo do vetor."},
    {id:154, stage:4, difficulty:'easy', category:'raiva', theme:'emergência', q:"Pessoa mordida por cão com suspeita de raiva. Atitude correta:", alt:["Esperar sintomas aparecerem","Tomar antibióticos em casa","Procurar imediatamente atendimento médico","Apenas lavar o local com água","Ignorar o ferimento"], c:2, e:"Profilaxia pós-exposição imediata (vacina/soro) é crucial. Sintomas neurológicos indicam fase fatal."},
    {id:155, stage:4, difficulty:'easy', category:'fake_news', theme:'identificação', q:"Mensagem nas redes sociais afirma que 'vacinas alteram DNA humano', sem estudos ou fontes confiáveis. Isso provavelmente é:", alt:["Pesquisa científica validada","Consenso médico","Fake news","Campanha oficial de vacinação","Propaganda hospitalar"], c:2, e:"Fake news: falta de fonte, promessa sensacionalista, contraria consenso científico. Checar antes de compartilhar."},
    {id:156, stage:4, difficulty:'medium', category:'vacinas', theme:'imunidade_coletiva', q:"Uma das maiores vantagens da vacinação coletiva é:", alt:["Impedir totalmente qualquer doença","Proteger somente quem está vacinado","Diminuir a circulação do agente causador na população","Substituir hábitos de higiene","Eliminar necessidade de médicos"], c:2, e:"Imunidade de rebanho: redução da transmissão protege indiretamente quem não pode se vacinar."},
    {id:157, stage:4, difficulty:'easy', category:'dengue', theme:'sintomas', q:"Pessoa com febre alta, manchas vermelhas e dores no corpo após picada de mosquito. Doença mais provável:", alt:["Tuberculose","Hanseníase","Dengue","Tétano","Cólera"], c:2, e:"Sintomas clássicos de dengue. Buscar atendimento para monitorar sinais de alarme (dor abdominal, sangramento)."},
    {id:158, stage:4, difficulty:'easy', category:'antibióticos', theme:'especificidade', q:"Aluno afirmou: 'Antibióticos são eficazes no tratamento da gripe'. A afirmação está:", alt:["Correta, porque gripe é bacteriana","Correta apenas em crianças","Incorreta, porque gripe é viral","Correta apenas em idosos","Correta somente em casos graves"], c:2, e:"Gripe é viral (influenza). Antibióticos não atuam contra vírus. Uso inadequado gera resistência bacteriana."},
    {id:159, stage:4, difficulty:'easy', category:'saneamento', theme:'impacto', q:"Comunidade sem coleta de lixo, rede de esgoto e água tratada apresenta maior risco de:", alt:["Prevenção de epidemias","Doenças transmissíveis","Imunidade coletiva","Redução de infecções","Eliminação de bactérias"], c:1, e:"Saneamento precário favorece doenças de veiculação hídrica e vetorial. Investimento em infraestrutura é prevenção."},
    {id:160, stage:4, difficulty:'medium', category:'síntese', theme:'afirmativas', q:"Analise: I-Vacinas previnem doenças. II-Aedes é vetor da dengue. III-Saneamento previne doenças. IV-Antibióticos funcionam contra qualquer vírus. Estão corretas:", alt:["Apenas I e II","Apenas III e IV","Apenas I, II e III","Apenas IV","Todas"], c:2, e:"I, II e III corretas. IV errada: antibióticos não atuam contra vírus. Atenção a generalizações incorretas."}
  ]
};